import React from 'react';
import ParamHeader from './ParamHeader';

function EnergyInput({ energy, onEnergyChange, paramIcons, onIconClick, buttonRefs }) {
  return (
    <div className="bg-white/60 backdrop-blur-sm rounded-2xl p-4 shadow-lg">
      <div className="flex items-center justify-between">
        <ParamHeader
          paramKey="energy"
          label="能量值"
          iconColor="text-green-500 fill-green-500"
          onIconClick={onIconClick}
          buttonRef={(el) => buttonRefs.current.energy = el}
        />
        <input
          type="number"
          min="0"
          max="100"
          value={energy}
          onChange={(e) => onEnergyChange(Math.min(100, Math.max(0, parseInt(e.target.value) || 0)))}
          className="w-20 px-3 py-2 bg-white rounded-xl border-2 border-green-300 text-center font-bold text-green-600 focus:outline-none focus:ring-2 focus:ring-green-400 focus:border-transparent"
        />
      </div>
    </div>
  );
}

export default EnergyInput;
